import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Router } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { AuthService } from '../../../core/services/auth.service';
import { MessageService } from '../../../shared/services/message.service';

@Component({
  selector: 'app-register',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  template: `
    <div class="auth-page">
      <div class="auth-container">
        <div class="auth-card">
          <div class="auth-header">
            <h1>Create Account</h1>
            <p>Join ShopHub today</p>
          </div>

          <form (ngSubmit)="onSubmit()" #registerForm="ngForm">
            <div class="form-group">
              <label>Full Name</label>
              <input type="text" [(ngModel)]="name" name="name" required
                placeholder="John Doe" class="form-control" />
            </div>
            <div class="form-group">
              <label>Email</label>
              <input type="email" [(ngModel)]="email" name="email" required
                placeholder="you@example.com" class="form-control" />
            </div>
            <div class="form-group">
              <label>Password</label>
              <div class="input-with-icon">
                <input [type]="showPassword ? 'text' : 'password'"
                  [(ngModel)]="password" name="password" required minlength="6"
                  placeholder="At least 6 characters" class="form-control" />
                <button type="button" class="toggle-pw" (click)="showPassword = !showPassword">
                  {{ showPassword ? '🙈' : '👁️' }}
                </button>
              </div>
            </div>
            <div class="form-group">
              <label>Confirm Password</label>
              <input [type]="showPassword ? 'text' : 'password'"
                [(ngModel)]="confirmPassword" name="confirmPassword" required
                placeholder="Repeat your password" class="form-control" />
            </div>
            <div class="terms">
              <input type="checkbox" [(ngModel)]="agreed" name="agreed" id="terms" />
              <label for="terms">I agree to the <a href="#">Terms of Service</a> and <a href="#">Privacy Policy</a></label>
            </div>
            <button type="submit" class="btn-submit" [disabled]="loading || !agreed">
              <span *ngIf="loading">Creating account...</span>
              <span *ngIf="!loading">Create Account</span>
            </button>
          </form>

          <p class="auth-footer">
            Already have an account? <a routerLink="/auth/login">Sign in</a>
          </p>
        </div>
      </div>
    </div>
  `,
  styles: [`
    .auth-page {
      min-height: 100vh; background: var(--bg-primary, #0f1123);
      display: flex; align-items: center; justify-content: center; padding: 20px;
    }
    .auth-container {
      width: 100%; max-width: 440px;
      animation: authPageIn 0.55s cubic-bezier(0.16,1,0.3,1) both;
    }
    @keyframes authPageIn {
      from { opacity: 0; transform: translateY(30px) scale(0.96); }
      to   { opacity: 1; transform: translateY(0) scale(1); }
    }
    .auth-card {
      background: #1e2235; border-radius: 20px; padding: 40px;
      border: 1px solid rgba(255,255,255,0.08);
      box-shadow: 0 24px 60px rgba(0,0,0,0.4);
    }
    .auth-header { text-align: center; margin-bottom: 32px; }
    .auth-header h1 { font-size: 1.8rem; font-weight: 700; color: #e8eaf6; margin-bottom: 8px; }
    .auth-header p { color: #9ca3af; }
    .alert { padding: 12px 16px; border-radius: 8px; margin-bottom: 16px; font-size: 0.9rem; animation: alertIn 0.3s ease both; }
    @keyframes alertIn { from{opacity:0;transform:translateY(-8px)} to{opacity:1;transform:translateY(0)} }
    .alert-error { background: rgba(220,38,38,0.1); color: #f87171; border: 1px solid rgba(239,68,68,0.3); }
    .alert-success { background: rgba(34,197,94,0.1); color: #4ade80; border: 1px solid rgba(34,197,94,0.3); }
    .form-group { margin-bottom: 20px; }
    .form-group label { display: block; margin-bottom: 6px; font-weight: 600; color: #c9cbdf; font-size: 0.9rem; }
    .form-control {
      width: 100%; padding: 12px 16px;
      border: 2px solid rgba(255,255,255,0.1); border-radius: 10px;
      font-size: 1rem; outline: none;
      transition: border-color 0.25s, box-shadow 0.25s;
      box-sizing: border-box; background: rgba(255,255,255,0.05); color: #e8eaf6;
    }
    .form-control:focus { border-color: #4f6ef7; box-shadow: 0 0 0 3px rgba(79,110,247,0.18); }
    .input-with-icon { position: relative; }
    .input-with-icon .form-control { padding-right: 48px; }
    .toggle-pw {
      position: absolute; right: 12px; top: 50%; transform: translateY(-50%);
      background: none; border: none; cursor: pointer; font-size: 1rem; color: #9ca3af;
      transition: color 0.2s;
    }
    .toggle-pw:hover { color: #e0e4ff; }
    .terms {
      display: flex; align-items: flex-start; gap: 8px;
      margin-bottom: 20px; font-size: 0.85rem; color: #9ca3af;
    }
    .terms input { margin-top: 2px; }
    .terms a { color: #a5b4fc; }
    .btn-submit {
      width: 100%; padding: 14px;
      background: linear-gradient(135deg, #4f6ef7, #8b5cf6);
      color: white; border: none; border-radius: 10px;
      font-size: 1rem; font-weight: 700; cursor: pointer;
      transition: all 0.25s cubic-bezier(0.34,1.56,0.64,1);
      box-shadow: 0 4px 18px rgba(79,110,247,0.35);
    }
    .btn-submit:hover:not(:disabled) { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(79,110,247,0.5); }
    .btn-submit:active:not(:disabled) { transform: scale(0.97); }
    .btn-submit:disabled { opacity: 0.6; cursor: not-allowed; }
    .auth-footer { text-align: center; color: #9ca3af; font-size: 0.9rem; margin-top: 20px; }
    .auth-footer a { color: #a5b4fc; font-weight: 600; text-decoration: none; }
    @media (max-width: 480px) { .auth-card { padding: 28px 20px; } }
  `]
})
export class RegisterComponent {
  name = '';
  email = '';
  password = '';
  confirmPassword = '';
  agreed = false;
  loading = false;
  showPassword = false;

  constructor(private authService: AuthService, private router: Router, private msgService: MessageService) {}

  onSubmit() {
    if (!this.name || !this.email || !this.password) {
      this.msgService.error('Please fill in all fields');
      return;
    }
    if (this.password !== this.confirmPassword) {
      this.msgService.error('Passwords do not match');
      return;
    }
    if (this.password.length < 6) {
      this.msgService.error('Password must be at least 6 characters');
      return;
    }
    this.loading = true;
    this.authService.register({ name: this.name, email: this.email, password: this.password }).subscribe({
      next: () => {
        this.loading = false;
        this.msgService.success('Account created successfully!');
        setTimeout(() => this.router.navigate(['/']), 1500);
      },
      error: (err) => {
        this.loading = false;
        this.msgService.error(err.error?.message || 'Registration failed');
      }
    });
  }
}
